class TreeNode {
    constructor(val, left=null, right=null) {
        this.val = val;
        this.left = left;
        this.right = right;
    }
}

function diameterOfBinaryTree(root) {
    function diameterHelper(node) {
        if (!node) return [0, 0];
        let [leftHeight, leftDiameter] = diameterHelper(node.left);
        let [rightHeight, rightDiameter] = diameterHelper(node.right);
        let maxHeight = 1 + Math.max(leftHeight, rightHeight);
        let maxDiameter = Math.max(leftHeight + rightHeight, Math.max(leftDiameter, rightDiameter));
        return [maxHeight, maxDiameter];
    }

    return diameterHelper(root)[1];
}
