public class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode() {}
    TreeNode(int val) { this.val = val; }
    TreeNode(int val, TreeNode left, TreeNode right) {
        this.val = val;
        this.left = left;
        this.right = right;
    }
}

public int[] diameterHelper(TreeNode root) {
    if (root == null) return new int[]{0, 0};
    int[] left = diameterHelper(root.left);
    int[] right = diameterHelper(root.right);
    int maxHeight = 1 + Math.max(left[0], right[0]);
    int maxDiameter = Math.max(left[0] + right[0], Math.max(left[1], right[1]));
    return new int[]{maxHeight, maxDiameter};
}

public int diameterOfBinaryTree(TreeNode root) {
    return diameterHelper(root)[1];
}
```

